import React from "react";

export default function Header() {
  return (
    <header className="header">
      <div className="header-inner">
        <p className="header-date">27 · Junho · 2026</p>
        <h1 className="header-title">Jéssica & Pedro</h1>
        <p className="header-subtitle">💍 como este dia não é só nosso, partilha momentos especiais com as pessoas que tanto gostam</p>

      </div>
      <div className="header-divider">❦</div>
    </header>
  );
}
